files.content:
:host {
  display: block;
  width: 100%;
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;
}

.message-composer {
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-050);
  width: 100%;
  margin: 0;
}

.message-composer__attachments:empty,
.message-composer__tools:empty {
  display: none;
}

.message-composer__field {
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-050);
  padding: var(--dimension-space-100);
  border-radius: var(--dimension-radius-125);
  background: var(--color-background-primary);
  box-shadow: var(--effect-elevation-elevated-md);
  overflow: hidden;
}

.message-composer:not(.message-composer--error) .message-composer__field:focus-within {
  box-shadow: var(--effect-elevation-elevated-md),
    inset 0 0 0 var(--dimension-stroke-width-018) var(--color-border-bold-brand);
}

.message-composer--error .message-composer__field {
  box-shadow: var(--effect-elevation-elevated-md),
    inset 0 0 0 var(--dimension-stroke-width-025) var(--color-border-bold-negative);
}

textarea {
  width: 100%;
  min-height: calc(var(--typography-lineheight-md) * 2 + var(--dimension-space-150));
  max-height: calc(var(--typography-lineheight-md) * 6 + var(--dimension-space-150));
  padding: var(--dimension-space-075);
  border: none;
  outline: none;
  resize: none;
  overflow-y: auto;
  box-sizing: border-box;
  background: transparent;
  color: var(--color-foreground-primary);
  font-family: var(--typography-font-family);
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
  font-weight: var(--typography-weight-regular);
  letter-spacing: var(--typography-letterspacing-negative-half);
  -webkit-user-select: text;
  user-select: text;
}

textarea::placeholder {
  color: var(--color-foreground-secondary);
}

textarea:focus::placeholder {
  color: var(--color-foreground-quaternary);
}

textarea:focus,
textarea:focus-visible {
  outline: none;
}

.message-composer__tools {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
  min-height: var(--dimension-size-400);
}

.message-composer__controls {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--dimension-space-050);
  width: 100%;
  min-width: 0;
}

.message-composer__actions {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-100);
  flex: 0 0 auto;
  margin-inline-start: auto;
}

import {
  Component,
  Element,
  Event,
  EventEmitter,
  h,
  Host,
  Method,
  Prop,
  Watch,
} from '@stencil/core';
import type { ButtonFilledIntent } from '../ButtonFilled/ButtonFilled';
import type { MessageComposerStatus } from '../conversation-types';

@Component({
  tag: 'ds-message-composer',
  styleUrl: 'MessageComposer.css',
  scoped: true,
})
export class MessageComposer {
  @Element() el!: HTMLElement;

  @Prop({ mutable: true }) value: string = '';
  @Prop() placeholder: string = 'Write a message';
  @Prop() label: string = 'Message';
  @Prop() status: MessageComposerStatus = 'ready';
  @Prop() isInactive: boolean = false;
  @Prop() submitIntent: ButtonFilledIntent = 'brand';

  @Event() dsInput!: EventEmitter<string>;
  @Event() dsSubmit!: EventEmitter<{ text: string }>;
  @Event() dsStop!: EventEmitter<void>;

  private textarea?: HTMLTextAreaElement;

  componentDidLoad() {
    this.resize();
  }

  @Watch('value')
  onValueChange() {
    requestAnimationFrame(() => this.resize());
  }

  @Method()
  async setFocus() {
    this.textarea?.focus();
  }

  private get streaming(): boolean {
    return this.status === 'submitted' || this.status === 'streaming';
  }

  private resize() {
    if (!this.textarea) return;
    this.textarea.style.height = 'auto';
    this.textarea.style.height = `${this.textarea.scrollHeight}px`;
  }

  private handleInput = (event: Event) => {
    this.value = (event.target as HTMLTextAreaElement).value;
    this.resize();
    this.dsInput.emit(this.value);
  };

  private submit() {
    const text = this.value.trim();
    if (!text || this.isInactive || this.streaming) return;
    this.dsSubmit.emit({ text });
  }

  private handleKeyDown = (event: KeyboardEvent) => {
    if (event.key !== 'Enter' || event.shiftKey || event.isComposing) return;
    event.preventDefault();
    this.submit();
  };

  private handleAction = () => {
    if (this.streaming) this.dsStop.emit();
    else this.submit();
  };

  render() {
    const error = this.status === 'error';
    const actionInactive = !this.streaming && (this.isInactive || !this.value.trim());
    return (
      <Host>
        <form
          class={{ 'message-composer': true, 'message-composer--error': error }}
          aria-busy={this.streaming ? 'true' : undefined}
          onSubmit={(event: Event) => {
            event.preventDefault();
            this.submit();
          }}
        >
          <div class="message-composer__attachments">
            <slot name="attachments" />
          </div>
          <div class="message-composer__field">
            <textarea
              ref={element => {
                this.textarea = element;
              }}
              value={this.value}
              placeholder={this.placeholder}
              aria-label={this.label}
              aria-invalid={error ? 'true' : undefined}
              disabled={this.isInactive}
              rows={2}
              onInput={this.handleInput}
              onKeyDown={this.handleKeyDown}
            />
            <div class="message-composer__controls">
              <div class="message-composer__tools">
                <slot name="tools" />
              </div>
              <div class="message-composer__actions">
                <slot name="actions" />
                {actionInactive ? (
                  <ds-tooltip label="Send message" side="top" size="sm">
                    <ds-button-unfilled
                      class="message-composer__action"
                      variant="icon"
                      icon="ArrowUp"
                      size="md"
                      aria-label="Send message"
                      hasBorder
                      isInactive
                      onDsClick={this.handleAction}
                    />
                  </ds-tooltip>
                ) : (
                  <ds-tooltip
                    label={this.streaming ? 'Stop response' : 'Send message'}
                    side="top"
                    size="sm"
                  >
                    <ds-button-filled
                      class="message-composer__action"
                      variant="icon"
                      icon={this.streaming ? 'SquareFilled' : 'ArrowUp'}
                      intent={this.streaming ? 'brand' : this.submitIntent}
                      contrast="bold"
                      size="md"
                      aria-label={this.streaming ? 'Stop response' : 'Send message'}
                      onDsClick={this.handleAction}
                    />
                  </ds-tooltip>
                )}
              </div>
            </div>
          </div>
        </form>
      </Host>
    );
  }
}
